// MARK: - Models

struct Stock: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Decimal
    var previousClose: Decimal
    var volume: Int64
    var lastUpdated: Date
    
    var changePercent: Decimal {
        guard previousClose != 0 else { return 0 }
        return ((currentPrice - previousClose) / previousClose) * 100
    }
}

struct Position: Codable, Identifiable {
    let id: String
    let symbol: String
    let quantity: Decimal
    let averageCostBasis: Decimal
    let currentPrice: Decimal
    var marketValue: Decimal { quantity * currentPrice }
    var totalGainLoss: Decimal { (currentPrice - averageCostBasis) * quantity }
    var gainLossPercent: Decimal {
        guard averageCostBasis != 0 else { return 0 }
        return ((currentPrice - averageCostBasis) / averageCostBasis) * 100
    }
}

struct Portfolio: Codable {
    let accountId: String
    var cashBalance: Decimal
    var positions: [Position]
    var totalValue: Decimal {
        cashBalance + positions.reduce(0) { $0 + $1.marketValue }
    }
    var totalGainLoss: Decimal {
        positions.reduce(0) { $0 + $1.totalGainLoss }
    }
}

