// MARK: - Trading Errors

enum TradingError: Error, LocalizedError {
    case insufficientFunds(required: Decimal, available: Decimal)
    case insufficientShares(required: Decimal, available: Decimal)
    case invalidQuantity
    case invalidPrice
    case symbolNotFound
    case marketClosed
    case orderRejected(reason: String)
    case networkError(underlying: Error)
    case authenticationFailed
    case rateLimited
    case serverError(statusCode: Int)
    case certificatePinningFailed
    case encryptionError
    case inputValidationFailed(String)
    
    var errorDescription: String? {
        switch self {
        case .insufficientFunds(let required, let available):
            return "Insufficient funds. Required: \(required), Available: \(available)"
        case .insufficientShares(let required, let available):
            return "Insufficient shares. Required: \(required), Available: \(available)"
        case .invalidQuantity:
            return "Invalid order quantity"
        case .invalidPrice:
            return "Invalid price specified"
        case .symbolNotFound:
            return "Stock symbol not found"
        case .marketClosed:
            return "Market is currently closed"
        case .orderRejected(let reason):
            return "Order rejected: \(reason)"
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .authenticationFailed:
            return "Authentication failed. Please log in again."
        case .rateLimited:
            return "Too many requests. Please try again later."
        case .serverError(let code):
            return "Server error (HTTP \(code))"
        case .certificatePinningFailed:
            return "Secure connection could not be established"
        case .encryptionError:
            return "Data encryption error"
        case .inputValidationFailed(let msg):
            return "Validation failed: \(msg)"
        }
    }
}

// MARK: - Secure Keychain Manager

final class SecureKeychainManager {
    static let shared = SecureKeychainManager()
    private let serviceName = "com.tradingapp.secure"
    
    private init() {}
    
    func store(key: String, data: Data) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw TradingError.encryptionError
        }
    }
    
    func retrieve(key: String) throws -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess else {
            if status == errSecItemNotFound { return nil }
            throw TradingError.encryptionError
        }
        
        return result as? Data
    }
    
    func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
    
    func storeToken(_ token: String) throws {
        guard let data = token.data(using: .utf8) else {
            throw TradingError.encryptionError
        }
        try store(key: "auth_token", data: data)
    }
    
    func retrieveToken() throws -> String? {
        guard let data = try retrieve(key: "auth_token") else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func clearAll() {
        delete(key: "auth_token")
        delete(key: "refresh_token")
    }
}

// MARK: - Certificate Pinning Session Delegate

final class CertificatePinningDelegate: NSObject, URLSessionDelegate {
    private let pinnedCertificateHashes: Set<String>
    
    init(pinnedHashes: Set<String>) {
        self.pinnedCertificateHashes = pinnedHashes
        super.init()
    }
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        guard let certificateChain = SecTrustCopyCertificateChain(serverTrust) as? [SecCertificate],
              !certificateChain.isEmpty else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        var pinMatched = false
        for certificate in certificateChain {
            let certData = SecCertificateCopyData(certificate) as Data
            let hash = SHA256.hash(data: certData)
            let hashString = hash.compactMap { String(format: "%02x", $0) }.joined()
            
            if pinnedCertificateHashes.contains(hashString) {
                pinMatched = true
                break
            }
        }
        
        if pinMatched {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - Input Validator

struct InputValidator {
    private static let symbolPattern = "^[A-Z]{1,5}$"
    
    static func validateSymbol(_ symbol: String) throws -> String {
        let trimmed = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard let regex = try? NSRegularExpression(pattern: symbolPattern),
              regex.firstMatch(in: trimmed, range: NSRange(trimmed.startIndex..., in: trimmed)) != nil else {
            throw TradingError.inputValidationFailed("Invalid stock symbol format")
        }
        return trimmed
    }
    
    static func validateQuantity(_ quantity: Decimal) throws {
        guard quantity > 0 else {
            throw TradingError.invalidQuantity
        }
        guard quantity <= 1_000_000 else {
            throw TradingError.inputValidationFailed("Quantity exceeds maximum allowed")
        }
        // Ensure no more than 6 decimal places
        let handler = NSDecimalNumberHandler(roundingMode: .plain, scale: 6,
                                              raiseOnExactness: false, raiseOnOverflow: false,
                                              raiseOnUnderflow: false, raiseOnDivideByZero: false)
        let rounded = NSDecimalNumber(decimal: quantity).rounding(accordingToBehavior: handler).decimalValue
        guard rounded == quantity else {
            throw TradingError.inputValidationFailed("Quantity has too many decimal places")
        }
    }
    
    static func validatePrice(_ price: Decimal) throws {
        guard price > 0 else {
            throw TradingError.invalidPrice
        }
        guard price <= 1_000_000 else {
            throw TradingError.inputValidationFailed("Price exceeds maximum allowed")
        }
    }
}

// MARK: - Rate Limiter

actor RateLimiter {
    private var requestTimestamps: [Date] = []
    private let maxRequests: Int
    private let windowSeconds: TimeInterval
    
    init(maxRequests: Int = 30, windowSeconds: TimeInterval = 60) {
        self.maxRequests = maxRequests
        self.windowSeconds = windowSeconds
    }
    
    func shouldAllowRequest() -> Bool {
        let now = Date()
        let windowStart = now.addingTimeInterval(-windowSeconds)
        requestTimestamps = requestTimestamps.filter { $0 > windowStart }
        
        guard requestTimestamps.count < maxRequests else {
            return false
        }
        
        requestTimestamps.append(now)
        return true
    }
}

// MARK: - Secure API Client

final class SecureAPIClient {
    private let baseURL: URL
    private let session: URLSession
    private let keychainManager: SecureKeychainManager
    private let rateLimiter = RateLimiter()
    private let jsonEncoder: JSONEncoder
    private let jsonDecoder: JSONDecoder
    
    init(baseURL: URL, pinnedCertificateHashes: Set<String>) {
        self.baseURL = baseURL
        self.keychainManager = SecureKeychainManager.shared
        
        let pinningDelegate = CertificatePinningDelegate(pinnedHashes: pinnedCertificateHashes)
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        ]
        
        self.session = URLSession(configuration: config, delegate: pinningDelegate, delegateQueue: nil)
        
        self.jsonEncoder = JSONEncoder()
        self.jsonEncoder.dateEncodingStrategy = .iso8601
        
        self.jsonDecoder = JSONDecoder()
        self.jsonDecoder.dateDecodingStrategy = .iso8601
    }
    
    private func createSignature(for body: Data, timestamp: String, nonce: String) throws -> String {
        guard let secretData = try keychainManager.retrieve(key: "api_secret") else {
            throw TradingError.authenticationFailed
        }
        
        let payload = timestamp + nonce + body.base64EncodedString()
        guard let payloadData = payload.data(using: .utf8) else {
            throw TradingError.encryptionError
        }
        
        let key = SymmetricKey(data: secretData)
        let signature = HMAC<SHA256>.authenticationCode(for: payloadData, using: key)
        return Data(signature).base64EncodedString()
    }
    
    func request<T: Codable>(_ endpoint: String, method: String = "GET",
                              body: Encodable? = nil) async throws -> T {
        guard await rateLimiter.shouldAllowRequest() else {
            throw TradingError.rateLimited
        }
        
        let url = baseURL.appendingPathComponent(endpoint)
        var request = URLRequest(url: url)
        request.httpMethod = method
        
        // Auth token
        if let token = try keychainManager.retrieveToken() {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        // Request signing
        let timestamp = String(Int(Date().timeIntervalSince1970))
        let nonce = UUID().uuidString
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        request.setValue(nonce, forHTTPHeaderField: "X-Nonce")
        
        var bodyData = Data()
        if let body = body {
            bodyData = try jsonEncoder.encode(body)
            request.httpBody = bodyData
        }
        
        if let signature = try? createSignature(for: bodyData, timestamp: timestamp, nonce: nonce) {
            request.setValue(signature, forHTTPHeaderField: "X-Signature")
        }
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw TradingError.networkError(underlying: URLError(.badServerResponse))
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            let apiResponse = try jsonDecoder.decode(APIResponse<T>.self, from: data)
            if let error = apiResponse.error {
                throw error
            }
            guard let responseData = apiResponse.data else {
                throw TradingError.serverError(statusCode: httpResponse.statusCode)
            }
            return responseData
        case 401:
            throw TradingError.authenticationFailed
        case 429:
            throw TradingError.rateLimited
        default:
            throw TradingError.serverError(statusCode: httpResponse.statusCode)
        }
    }
}

// MARK: - WebSocket Price Feed

protocol PriceFeedDelegate: AnyObject {
    func priceFeedDidReceiveUpdate(_ update: PriceUpdate)
    func priceFeedDidDisconnect(error: Error?)
}

struct PriceUpdate: Codable {
    let symbol: String
    let price: Decimal
    let volume: Int64
    let timestamp: Date
}

final class WebSocketPriceFeed: NSObject, URLSessionWebSocketDelegate {
    private var webSocketTask: URLSessionWebSocketTask?
    private let url: URL
    private var subscribedSymbols: Set<String> = []
    weak var delegate: PriceFeedDelegate?
    private var isConnected = false
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    private let jsonDecoder: JSONDecoder
    
    init(url: URL) {
        self.url = url
        self.jsonDecoder = JSONDecoder()
        self.jsonDecoder.dateDecodingStrategy = .iso8601
        super.init()
    }
    
    func connect() {
        let config = URLSessionConfiguration.default
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        let session = URLSession(configuration: config, delegate: self, delegateQueue: nil)
        webSocketTask = session.webSocketTask(with: url)
        webSocketTask?.resume()
        isConnected = true
        reconnectAttempts = 0
        receiveMessage()
    }
    
    func disconnect() {
        isConnected = false
        webSocketTask?.cancel(with: .goingAway, reason: nil)
        webSocketTask = nil
    }
    
    func subscribe(to symbols: [String]) {
        let validSymbols = symbols.compactMap { try? InputValidator.validateSymbol($0) }
        subscribedSymbols.formUnion(validSymbols)
        
        let message: [String: Any] = [
            "action": "subscribe",
            "symbols": Array(subscribedSymbols)
        ]
        
        if let data = try? JSONSerialization.data(withJSONObject: message) {
            webSocketTask?.send(.data(data)) { [weak self] error in
                if let error = error {
                    self?.delegate?.priceFeedDidDisconnect(error: error)
                }
            }
        }
    }
    
    func unsubscribe(from symbols: [String]) {
        subscribedSymbols.subtract(symbols)
        
        let message: [String: Any] = [
            "action": "unsubscribe",
            "symbols": symbols
        ]
        
        if let data = try? JSONSerialization.data(withJSONObject: message) {
            webSocketTask?.send(.data(data)) { _ in }
        }
    }
    
    private func receiveMessage() {
        webSocketTask?.receive { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let message):
                switch message {
                case .data(let data):
                    if let update = try? self.jsonDecoder.decode(PriceUpdate.self, from: data) {
                        DispatchQueue.main.async {
                            self.delegate?.priceFeedDidReceiveUpdate(update)
                        }
                    }
                case .string(let text):
                    if let data = text.data(using: .utf8),
                       let update = try? self.jsonDecoder.decode(PriceUpdate.self, from: data) {
                        DispatchQueue.main.async {
                            self.delegate?.priceFeedDidReceiveUpdate(update)
                        }
                    }
                @unknown default:
                    break
                }
                self.receiveMessage()
                
            case .failure(let error):
                self.handleDisconnection(error: error)
            }
        }
    }
    
    private func handleDisconnection(error: Error?) {
        isConnected = false
        delegate?.priceFeedDidDisconnect(error: error)
        attemptReconnect()
    }
    
    private func attemptReconnect() {
        guard reconnectAttempts < maxReconnectAttempts else { return }
        reconnectAttempts += 1
        let delay = pow(2.0, Double(reconnectAttempts))
        
        DispatchQueue.global().asyncAfter(deadline: .now() + delay) { [weak self] in
            self?.connect()
            if let symbols = self?.subscribedSymbols, !symbols.isEmpty {
                self?.subscribe(to: Array(symbols))
            }
        }
    }
    
    // MARK: - URLSessionWebSocketDelegate
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask,
                    didOpenWithProtocol protocol: String?) {
        isConnected = true
    }
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask,
                    didCloseWith closeCode: URLSessionWebSocketTask.CloseCode, reason: Data?) {
        handleDisconnection(error: nil)
    }
}

// MARK: - Trade Execution Engine

actor TradeExecutionEngine {
    private let apiClient: SecureAPIClient
    private var pendingOrders: [String: TradeOrder] = [:]
    private var processedIdempotencyKeys: Set<String> = []
    
    init(apiClient: SecureAPIClient) {
        self.apiClient = apiClient
    }
    
    func validateAndExecute(request: TradeRequest, portfolio: Portfolio) async throws -> TradeOrder {
        // Idempotency check
        guard !processedIdempotencyKeys.contains(request.idempotencyKey) else {
            throw TradingError.orderRejected(reason: "Duplicate order detected")
        }
        
        // Input validation
        let validatedSymbol = try InputValidator.validateSymbol(request.symbol)
        try InputValidator.validateQuantity(request.quantity)
        
        if let limitPrice = request.limitPrice {
            try InputValidator.validatePrice(limitPrice)
        }
        if let stopPrice = request.stopPrice {
            try InputValidator.validatePrice(stopPrice)
        }
        
        // Order type validation
        switch request.type {
        case .limit:
            guard request.limitPrice != nil else {
                throw TradingError.inputValidationFailed("Limit price required for limit orders")
            }
        case .stopLoss:
            guard request.stopPrice != nil else {
                throw TradingError.inputValidationFailed("Stop price required for stop loss orders")
            }
        case .stopLimit:
            guard request.limitPrice != nil, request.stopPrice != nil else {
                throw TradingError.inputValidationFailed("Both limit and stop prices required for stop limit orders")
            }
        case .market:
            break
        }
        
        // Pre-trade risk checks
        try performRiskChecks(request: request, portfolio: portfolio)
        
        // Mark idempotency key as processed
        processedIdempotencyKeys.insert(request.idempotencyKey)
        
        // Execute via API
        let sanitizedRequest = TradeRequest(
            symbol: validatedSymbol,
            side: request.side,
            type: request.type,
            quantity: request.quantity,
            limitPrice: request.limitPrice,
            stopPrice: request.stopPrice,
            timeInForce: request.timeInForce
        )
        
        do {
            let order: TradeOrder = try await apiClient.request(
                "/api/v1/orders",
                method: "POST",
                body: sanitizedRequest
            )
            pendingOrders[order.id] = order
            return order
        } catch {
            // Remove idempotency key on failure so retry is possible
            processedIdempotencyKeys.remove(request.idempotencyKey)
            throw error
        }
    }
    
    private func performRiskChecks(request: TradeRequest, portfolio: Portfolio) throws {
        switch request.side {
        case .buy:
            let estimatedCost: Decimal
            if let limitPrice = request.limitPrice {
                estimatedCost = request.quantity * limitPrice
            } else {
                // For market orders, use a buffer
                estimatedCost = request.quantity * 1_000_000 // Will be validated server-side
            }
            
            if request.type == .limit || request.type == .stopLimit {
                guard estimatedCost <= portfolio.cashBalance else {
                    throw TradingError.insufficientFunds(required: estimatedCost, available: portfolio.cashBalance)
                }
            }
            
        case .sell:
            let position = portfolio.positions.first { $0.symbol == request.symbol.uppercased() }
            let availableQuantity = position?.quantity ?? 0
            guard request.quantity <= availableQuantity else {
                throw TradingError.insufficientShares(required: request.quantity, available: availableQuantity)
            }
        }
        
        // Position concentration check (max 25% of portfolio in single stock)
        let maxPositionValue = portfolio.totalValue * Decimal(0.25)
        if request.side == .buy, let limitPrice = request.limitPrice {
            let existingPosition = portfolio.positions.first { $0.symbol == request.symbol }
            let existingValue = existingPosition?.marketValue ?? 0
            let newValue = existingValue + (request.quantity * limitPrice)
            if newValue > maxPositionValue {
                throw TradingError.orderRejected(reason: "Position would exceed 25% concentration limit")
            }
        }
    }
    
    func cancelOrder(orderId: String) async throws -> TradeOrder {
        let order: TradeOrder = try await apiClient.request(
            "/api/v1/orders/\(orderId)/cancel",
            method: "POST"
        )
        pendingOrders.removeValue(forKey: orderId)
        return order
    }
    
    func getOrderStatus(orderId: String) async throws -> TradeOrder {
        let order: TradeOrder = try await apiClient.request("/api/v1/orders/\(orderId)")
        if order.status == .filled || order.status == .cancelled || order.status == .rejected {
            pendingOrders.removeValue(forKey: orderId)
        }
        return order
    }
    
    func getPendingOrders() -> [TradeOrder] {
        Array(pendingOrders.values)
    }
}

// MARK: - Portfolio Manager

final class PortfolioManager: ObservableObject {
    @Published private(set) var portfolio: Portfolio?
    @Published private(set) var isLoading = false
    @Published private(set) var error: TradingError?
    @Published private(set) var orderHistory: [TradeOrder] = []
    
    private let apiClient: SecureAPIClient
    private let tradeEngine: TradeExecutionEngine
    private var refreshTimer: Timer?
    
    init(apiClient: SecureAPIClient) {
        self.apiClient = apiClient
        self.tradeEngine = TradeExecutionEngine(apiClient: apiClient)
    }
    
    func startAutoRefresh(interval: TimeInterval = 15) {
        refreshTimer?.invalidate()
        refreshTimer = Timer.scheduledTimer(withTimeInterval: interval, repeats: true) { [weak self] _ in
            Task { [weak self] in
                await self?.refreshPortfolio()
            }
        }
    }
    
    func stopAutoRefresh() {
        refreshTimer?.invalidate()
        refreshTimer = nil
    }
    
    @MainActor
    func refreshPortfolio() async {
        isLoading = true
        error = nil
        
        do {
            let fetchedPortfolio: Portfolio = try await apiClient.request("/api/v1/portfolio")
            self.portfolio = fetchedPortfolio
        } catch let tradingError as TradingError {
            self.error = tradingError
        } catch {
            self.error = .networkError(underlying: error)
        }
        
        isLoading = false
    }
    
    @MainActor
    func executeTrade(request: TradeRequest) async throws -> TradeOrder {
        guard let portfolio = portfolio else {
            throw TradingError.orderRejected(reason: "Portfolio not loaded")
        }
        
        let order = try await tradeEngine.validateAndExecute(request: request, portfolio: portfolio)
        
        // Refresh portfolio after trade
        await refreshPortfolio()
        await refreshOrderHistory()
        
        return order
    }
    
    @MainActor
    func cancelOrder(orderId: String) async throws -> TradeOrder {
        let order = try await tradeEngine.cancelOrder(orderId: orderId)
        await refreshOrderHistory()
        return order
    }
    
    @MainActor
    func refreshOrderHistory() async {
        do {
            let orders: [TradeOrder] = try await apiClient.request("/api/v1/orders")
            self.orderHistory = orders.sorted { $0.createdAt > $1.createdAt }
        } catch {
            // Silently fail for order history refresh
        }
    }
    
    deinit {
        refreshTimer?.invalidate()
    }
}

