    @Published private(set) var isSearching = false
    
    private let apiClient: SecureAPIClient
    private let priceFeed: WebSocketPriceFeed
    private var searchTask: Task<Void, Never>?
    
    init(apiClient: SecureAPIClient, priceFeed: WebSocketPriceFeed) {
        self.apiClient = apiClient
        self.priceFeed = priceFeed
    }
    
    @MainActor
    func search(query: String) async {
        searchTask?.cancel()
        
        let trimmed = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty, trimmed.count <= 50 else {
            searchResults = []
            return
        }
        
        // Sanitize input - only allow alphanumeric and spaces
        let sanitized = trimmed.filter { $0.isLetter || $0.isNumber || $0 == " " }
        guard !sanitized.isEmpty else {
            searchResults = []
            return
        }
        
        isSearching = true
        
        searchTask = Task {
            // Debounce
            try? await Task.sleep(nanoseconds: 300_000_000)
            guard !Task.isCancelled else { return }
            
            do {
                let encodedQuery = sanitized.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? ""
                let results: [Stock] = try await apiClient.request("/api/v1/stocks/search?q=\(encodedQuery)")
                if !Task.isCancelled {
                    self.searchResults = results
                }
            } catch {
                if !Task.isCancelled {
                    self.searchResults = []
                }
            }
            
            self.isSearching = false
        }
    }
    
    @MainActor
    func getQuote(symbol: String) async throws -> Stock {
        let validatedSymbol = try InputValidator.validateSymbol(symbol)
        return try await apiClient.request("/api/v1/stocks/\(validatedSymbol)/quote")
    }
    
    @MainActor
    func loadWatchlist() async {
        do {
            let stocks: [Stock] = try await apiClient.request("/api/v1/watchlist")
            self.watchlist = stocks
            priceFeed.subscribe(to: stocks.map { $0.symbol })
        } catch {
            // Handle silently
        }
    }
    
    @MainActor
    func addToWatchlist(symbol: String) async throws {
        let validatedSymbol = try InputValidator.validateSymbol(symbol)
        let _: Stock = try await apiClient.request(
            "/api/v1/watchlist",
            method: "POST",
            body: ["symbol": validatedSymbol]
        )
        await loadWatchlist()
    }
    
    @MainActor
    func removeFromWatchlist(symbol: String) async throws {
        let validatedSymbol = try InputValidator.validateSymbol(symbol)
        let _: [String: Bool] = try await apiClient.request(
            "/api/v1/watchlist/\(validatedSymbol)",
            method: "DELETE"
        )
        priceFeed.unsubscribe(from: [validatedSymbol])
        await loadWatchlist()
    }
    
    func updatePrice(_ update: PriceUpdate) {
        DispatchQueue.main.async { [weak self] in
            if let index = self?.watchlist.firstIndex(where: { $0.symbol == update.symbol }) {
                self?.watchlist[index].currentPrice = update.price
                self?.watchlist[index].volume = update.volume
                self?.watchlist[index].lastUpdated = update.timestamp
            }
        }
    }
}

// MARK: - Authentication Manager

final class AuthenticationManager: ObservableObject {
    @Published private(set) var isAuthenticated = false
    @Published private(set) var isLoading = false
    
    private let keychainManager = SecureKeychainManager.shared
    private let apiClient: SecureAPIClient
    
    init(apiClient: SecureAPIClient) {
        self.apiClient = apiClient
        checkExistingSession()
    }
    
    private func checkExistingSession() {
        do {
            isAuthenticated = try keychainManager.retrieveToken() != nil
        } catch {
            isAuthenticated = false
        }
    }
    
    struct LoginRequest: Codable {
        let email: String
        let password: String
        let deviceId: String
    }
    
    struct AuthResponse: Codable {
        let accessToken: String
        let refreshToken: String
        let expiresIn: Int
    }
    
    @MainActor
    func login(email: String, password: String) async throws {
        // Validate email format
        let emailRegex = "^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$"
        guard let regex = try? NSRegularExpression(pattern: emailRegex),
              regex.firstMatch(in: email, range: NSRange(email.startIndex..., in: email)) != nil else {
            throw TradingError.inputValidationFailed("Invalid email format")
        }
        
        guard password.count >= 8 else {
            throw TradingError.inputValidationFailed("Password must be at least 8 characters")
        }
        
        isLoading = true
        defer { isLoading = false }
        
        let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? UUID().uuidString
        
        let loginRequest = LoginRequest(email: email, password: password, deviceId: deviceId)
        
        let response: AuthResponse = try await apiClient.request(
            "/api/v1/auth/login",
            method: "POST",
            body: loginRequest
        )
        
        try keychainManager.storeToken(response.accessToken)
        if let refreshData = response.refreshToken.data(using: .utf8) {
            try keychainManager.store(key: "refresh_token", data: refreshData)
        }
        
        isAuthenticated = true
    }
    
    @MainActor
    func logout() {
        keychainManager.clearAll()
        isAuthenticated = false
    }
    
    func refreshTokenIfNeeded() async throws {
        guard let refreshData = try keychainManager.retrieve(key: "refresh_token"),
              let refreshToken = String(data: refreshData, encoding: .utf8) else {
            throw TradingError.authenticationFailed
        }
        
        let response: AuthResponse = try await apiClient.request(
            "/api/v1/auth/refresh",
            method: "POST",
            body: ["refreshToken": refreshToken]
        )
        
        try keychainManager.storeToken(response.accessToken)
        if let newRefreshData = response.refreshToken.data(using: .utf8) {
            try keychainManager.store(key: "refresh_token", data: newRefreshData)
        }
    }
}

