struct TradeView: View {
    @EnvironmentObject var portfolioManager: PortfolioManager
    @EnvironmentObject var stockService: StockService
    
    @State private var symbol = ""
    @State private var quantityText = ""
    @State private var limitPriceText = ""
    @State private var stopPriceText = ""
    @State private var selectedSide: OrderSide = .buy
    @State private var selectedOrderType: OrderType = .market
    @State private var selectedTimeInForce: TimeInForce = .day
    @State private var currentQuote: Stock?
    @State private var isExecuting = false
    @State private var showConfirmation = false
    @State private var showResult = false
    @State private var resultOrder: TradeOrder?
    @State private var errorMessage: String?
    @State private var showError = false
    
    var body: some View {
        NavigationView {
            Form {
                Section("Symbol") {
                    TextField("Enter symbol (e.g., AAPL)", text: $symbol)
                        .autocapitalization(.allCharacters)
                        .disableAutocorrection(true)
                        .onChange(of: symbol) { newValue in
                            if newValue.count >= 1 {
                                Task { await fetchQuote() }
                            } else {
                                currentQuote = nil
                            }
                        }
                    
                    if let quote = currentQuote {
                        HStack {
                            Text(quote.name)
                                .font(.caption)
                            Spacer()
                            VStack(alignment: .trailing) {
                                Text(formatCurrency(quote.currentPrice))
                                    .fontWeight(.bold)
                                Text("\(formatPercent(quote.changePercent))")
                                    .font(.caption)
                                    .foregroundColor(quote.changePercent >= 0 ? .green : .red)
                            }
                        }
                    }
                }
                
                Section("Order Details") {
                    Picker("Side", selection: $selectedSide) {
                        Text("Buy").tag(OrderSide.buy)
                        Text("Sell").tag(OrderSide.sell)
                    }
                    .pickerStyle(.segmented)
                    
                    Picker("Order Type", selection: $selectedOrderType) {
                        Text("Market").tag(OrderType.market)
                        Text("Limit").tag(OrderType.limit)
                        Text("Stop Loss").tag(OrderType.stopLoss)
                        Text("Stop Limit").tag(OrderType.stopLimit)
                    }
                    
                    TextField("Quantity", text: $quantityText)
                        .keyboardType(.decimalPad)
                    
                    if selectedOrderType == .limit || selectedOrderType == .stopLimit {
                        TextField("Limit Price", text: $limitPriceText)
                            .keyboardType(.decimalPad)
                    }
                    
                    if selectedOrderType == .stopLoss || selectedOrderType == .stopLimit {
                        TextField("Stop Price", text: $stopPriceText)
                            .keyboardType(.decimalPad)
                    }
                    
                    Picker("Time in Force", selection: $selectedTimeInForce) {
                        Text("Day").tag(TimeInForce.day)
                        Text("GTC").tag(TimeInForce.gtc)
                        Text("IOC").tag(TimeInForce.ioc)
                        Text("FOK").tag(TimeInForce.fok)
                    }
                }
                
                if let estimatedCost = calculateEstimatedCost() {
                    Section("Order Summary") {
                        HStack {
                            Text("Estimated \(selectedSide == .buy ? "Cost" : "Proceeds")")
                            Spacer()
                            Text(formatCurrency(estimatedCost))
                                .fontWeight(.bold)
                        }
                        
                        if let portfolio = portfolioManager.portfolio, selectedSide == .buy {
                            HStack {
                                Text("Available Cash")
                                Spacer()
                                Text(formatCurrency(portfolio.cashBalance))
                                    .foregroundColor(portfolio.cashBalance >= estimatedCost ? .green : .red)
                            }
                        }
                    }
                }
                
                Section {
                    Button(action: { showConfirmation = true }) {
                        HStack {
                            Spacer()
                            if isExecuting {
                                ProgressView()
                            } else {
                                Text(selectedSide == .buy ? "Place Buy Order" : "Place Sell Order")
                                    .fontWeight(.bold)
                            }
                            Spacer()
                        }
                    }
                    .disabled(!isValidOrder || isExecuting)
                    .foregroundColor(selectedSide == .buy ? .green : .red)
                }
            }
            .navigationTitle("Trade")
            .confirmationDialog("Confirm Order", isPresented: $showConfirmation) {
                Button("Confirm \(selectedSide.rawValue) Order", role: selectedSide == .sell ? .destructive : nil) {
                    executeTrade()
                }
                Button("Cancel", role: .cancel) {}
            } message: {
                Text("Are you sure you want to \(selectedSide.rawValue.lowercased()) \(quantityText) shares of \(symbol.uppercased())?")
            }
            .alert("Order Placed", isPresented: $showResult) {
                Button("OK") { resetForm() }
            } message: {
                if let order = resultOrder {
                    Text("Order \(order.id) has been \(order.status.rawValue.lowercased()).")
                }
            }
            .alert("Order Error", isPresented: $showError) {
                Button("OK") {}
            } message: {
                Text(errorMessage ?? "Unknown error")
            }
        }
    }
    
    private var isValidOrder: Bool {
        guard !symbol.isEmpty,
              let quantity = Decimal(string: quantityText),
              quantity > 0 else { return false }
        
        switch selectedOrderType {
        case .limit:
            guard let price = Decimal(string: limitPriceText), price > 0 else { return false }
        case .stopLoss:
            guard let price = Decimal(string: stopPriceText), price > 0 else { return false }
        case .stopLimit:
            guard let limitPrice = Decimal(string: limitPriceText), limitPrice > 0,
                  let stopPrice = Decimal(string: stopPriceText), stopPrice > 0 else { return false }
        case .market:
            break
        }
        
        return true
    }
    
    private func calculateEstimatedCost() -> Decimal? {
        guard let quantity = Decimal(string: quantityText), quantity > 0 else { return nil }
        
        let price: Decimal
        if let limitPrice = Decimal(string: limitPriceText), selectedOrderType == .limit || selectedOrderType == .stopLimit {
            price = limitPrice
        } else if let quote = currentQuote {
            price = quote.currentPrice
        } else {
            return nil
        }
        
        return quantity * price
    }
    
    private func fetchQuote() async {
        do {
            currentQuote = try await stockService.getQuote(symbol: symbol)
        } catch {
            currentQuote = nil
        }
    }
    
    private func executeTrade() {
        guard let quantity = Decimal(string: quantityText) else { return }
        
        let limitPrice = Decimal(string: limitPriceText)
        let stopPrice = Decimal(string: stopPriceText)
        
        let request = TradeRequest(
            symbol: symbol,
            side: selectedSide,
            type: selectedOrderType,
            quantity: quantity,
            limitPrice: limitPrice,
            stopPrice: stopPrice,
            timeInForce: selectedTimeInForce
        )
        
        isExecuting = true
        
        Task {
            do {
                let order = try await portfolioManager.executeTrade(request: request)
                await MainActor.run {
                    resultOrder = order
                    showResult = true
                    isExecuting = false
                }
            } catch {
                await MainActor.run {
                    errorMessage = error.localizedDescription
                    showError = true
                    isExecuting = false
                }
            }
        }
    }
    
    private func resetForm() {
        symbol = ""
        quantityText = ""
        limitPriceText = ""
        stopPriceText = ""
        currentQuote = nil
        selectedOrderType = .market
        selectedTimeInForce = .day
    }
    
    private func formatCurrency(_ value: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: value as NSDecimalNumber) ?? "$0.00"
    }
    
    private func formatPercent(_ value: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .decimal
        formatter.maximumFractionDigits = 2
        formatter.positivePrefix = "+"
        return (formatter.string(from: value as NSDecimalNumber) ?? "0") + "%"
    }
}

