                                        .foregroundColor(.secondary)
                                }
                                Spacer()
                                Image(systemName: "plus.circle")
                                    .foregroundColor(.blue)
                            }
                        }
                    }
                }
            }
            .searchable(text: $searchText, prompt: "Search stocks")
            .onChange(of: searchText) { newValue in
                Task { await stockService.search(query: newValue) }
            }
            .navigationTitle("Add Stock")
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
    
    private func addStock(_ symbol: String) {
        Task {
            try? await stockService.addToWatchlist(symbol: symbol)
            dismiss()
        }
    }
}

struct OrderHistoryView: View {
    @EnvironmentObject var portfolioManager: PortfolioManager
    
    var body: some View {
        NavigationView {
            List {
                if portfolioManager.orderHistory.isEmpty {
                    Text("No orders")
                        .foregroundColor(.secondary)
                } else {
                    ForEach(portfolioManager.orderHistory) { order in
                        OrderRow(order: order)
                    }
                }
            }
            .navigationTitle("Orders")
            .refreshable {
                await portfolioManager.refreshOrderHistory()
            }
            .task {
                await portfolioManager.refreshOrderHistory()
            }
        }
    }
}

